module TopModule (input in, input [9:0] state, output logic [9:0] next_state, output logic out1, output logic out2); localparam S0 = 10'b0000000001; localparam S1 = 10'b0000000010; localparam S2 = 10'b0000000100; localparam S3 = 10'b0000001000; localparam S4 = 10'b0000010000; localparam S5 = 10'b0000100000; localparam S6 = 10'b0001000000; localparam S7 = 10'b0010000000; localparam S8 = 10'b0100000000; localparam S9 = 10'b1000000000; always @(*) begin next_state[0] = (state[0] & ~in) | (state[4] & in) | (state[8] & in) | (state[9] & ~in); next_state[1] = (state[1] & in) | (state[8] & in); next_state[2] = (state[2] & ~in); next_state[3] = (state[2] & in) | (state[3] & ~in); next_state[4] = (state[4] & ~in); next_state[5] = (state[5] & in); next_state[6] = (state[6] & in); next_state[7] = (state[7] & ~in); next_state[8] = (state[8] & ~in); next_state[9] = (state[9] & ~in); end assign out1 = state[7] | state[8]; assign out2 = state[7] & state[8]; endmodule